from flask import Flask, render_template, redirect, url_for, request
import os
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

# Helper functions to load data from files

DATA_DIR = 'data'

CURRENT_USER = 'john_diner'  # Simulated logged-in user for all routes

# Load users data into dict by username

def load_users():
    users = {}
    users_path = os.path.join(DATA_DIR, 'users.txt')
    if not os.path.exists(users_path):
        return users
    with open(users_path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 4:
                username, email, phone, full_name = parts
                users[username] = {
                    'username': username,
                    'email': email,
                    'phone': phone,
                    'full_name': full_name
                }
    return users

# Load menu items into list of dicts

def load_menu():
    menu = []
    menu_path = os.path.join(DATA_DIR, 'menu.txt')
    if not os.path.exists(menu_path):
        return menu
    with open(menu_path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 8:
                dish_id = int(parts[0])
                name = parts[1]
                category = parts[2]
                try:
                    price = float(parts[3])
                except ValueError:
                    price = 0.0
                description = parts[4]
                ingredients = parts[5]
                dietary = parts[6]
                try:
                    avg_rating = float(parts[7])
                except ValueError:
                    avg_rating = 0.0
                menu.append({
                    'dish_id': dish_id,
                    'name': name,
                    'category': category,
                    'price': price,
                    'description': description,
                    'ingredients': ingredients,
                    'dietary': dietary,
                    'avg_rating': avg_rating
                })
    return menu

# Load reservations into list of dicts

def load_reservations():
    reservations = []
    res_path = os.path.join(DATA_DIR, 'reservations.txt')
    if not os.path.exists(res_path):
        return reservations
    with open(res_path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 10:
                try:
                    reservation_id = int(parts[0])
                    party_size = int(parts[5])
                except ValueError:
                    continue
                reservations.append({
                    'reservation_id': reservation_id,
                    'username': parts[1],
                    'guest_name': parts[2],
                    'phone': parts[3],
                    'email': parts[4],
                    'party_size': party_size,
                    'date': parts[6],
                    'time': parts[7],
                    'special_requests': parts[8],
                    'status': parts[9]
                })
    return reservations

# Load waitlist data into list of dicts

def load_waitlist():
    waitlist = []
    waitlist_path = os.path.join(DATA_DIR, 'waitlist.txt')
    if not os.path.exists(waitlist_path):
        return waitlist
    with open(waitlist_path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 5:
                try:
                    waitlist_id = int(parts[0])
                    party_size = int(parts[2])
                except ValueError:
                    continue
                waitlist.append({
                    'waitlist_id': waitlist_id,
                    'username': parts[1],
                    'party_size': party_size,
                    'join_time': parts[3],
                    'status': parts[4]
                })
