# Load reviews data into list of dicts

def load_reviews():
    reviews = []
    reviews_path = os.path.join(DATA_DIR, 'reviews.txt')
    if not os.path.exists(reviews_path):
        return reviews
    with open(reviews_path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 6:
                try:
                    review_id = int(parts[0])
                    dish_id = int(parts[2])
                    rating = int(parts[3])
                except ValueError:
                    continue
                reviews.append({
