    with open(users_path, 'w', encoding='utf-8') as f:
        for u in users.values():
            line = '|'.join([
                u['username'],
                u['email'],
                u['phone'],
                u['full_name']
            ]) + '\n'
            f.write(line)

# Route implementations

@app.route('/')
def root():
    return redirect(url_for('dashboard'))

@app.route('/dashboard')
def dashboard():
    users = load_users()
    username = CURRENT_USER
    user_info = users.get(username)
    # Featured dishes: top 3 by avg_rating descending
    menu = load_menu()
    sorted_menu = sorted(menu, key=lambda x: x['avg_rating'], reverse=True)
    featured_dishes = []
    for d in sorted_menu[:3]:
        featured_dishes.append({
            'dish_id': d['dish_id'],
            'name': d['name'],
            'price': d['price']
        })

    # Upcoming reservations for current user (status "Upcoming"), sorted by date/time
    reservations = load_reservations()
    upcoming_reservations = [r for r in reservations if r['username']==username and r['status']=='Upcoming']
    def datetime_key(r):
        # Combine date and time for sorting
        try:
            return datetime.strptime(r['date'] + ' ' + r['time'], '%Y-%m-%d %H:%M')
        except ValueError:
            return datetime.max
    upcoming_reservations.sort(key=datetime_key)
    upcoming_reservations_list = []
    for r in upcoming_reservations:
        upcoming_reservations_list.append({
            'reservation_id': r['reservation_id'],
            'date': r['date'],
            'time': r['time'],
            'party_size': r['party_size'],
            'status': r['status']
        })

    return render_template('dashboard.html', username=username, featured_dishes=featured_dishes, upcoming_reservations=upcoming_reservations_list)

@app.route('/menu')
def menu():
