from flask import Flask, render_template, redirect, url_for, request
import os
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

# Data directory
DATA_DIR = 'data'

# Simulated logged in user
CURRENT_USER = 'john_diner'

# Helper functions to load data

def load_users():
    users = {}
    path = os.path.join(DATA_DIR, 'users.txt')
    if not os.path.exists(path):
        return users
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 4:
                username, email, phone, full_name = parts
                users[username] = {
                    'username': username,
                    'email': email,
                    'phone': phone,
                    'full_name': full_name
                }
    return users


def load_menu():
    menu = []
    path = os.path.join(DATA_DIR, 'menu.txt')
    if not os.path.exists(path):
        return menu
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 8:
                try:
                    dish_id = int(parts[0])
                    price = float(parts[3])
                    avg_rating = float(parts[7])
                except ValueError:
                    continue
                name = parts[1]
                category = parts[2]
                description = parts[4]
                ingredients = parts[5]
                dietary = parts[6]
                menu.append({
                    'dish_id': dish_id,
                    'name': name,
                    'category': category,
                    'price': price,
                    'description': description,
                    'ingredients': ingredients,
                    'dietary': dietary,
                    'avg_rating': avg_rating
                })
    return menu


def load_reservations():
    reservations = []
    path = os.path.join(DATA_DIR, 'reservations.txt')
    if not os.path.exists(path):
        return reservations
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 10:
                try:
                    reservation_id = int(parts[0])
                    party_size = int(parts[5])
                except ValueError:
                    continue
                reservations.append({
                    'reservation_id': reservation_id,
                    'username': parts[1],
                    'guest_name': parts[2],
                    'phone': parts[3],
                    'email': parts[4],
                    'party_size': party_size,
                    'date': parts[6],
                    'time': parts[7],
                    'special_requests': parts[8],
                    'status': parts[9]
                })
    return reservations


def save_reservations(reservations):
    path = os.path.join(DATA_DIR, 'reservations.txt')
    with open(path, 'w', encoding='utf-8') as f:
        for r in reservations:
            line = '|'.join([
                str(r['reservation_id']),
                r['username'],
                r['guest_name'],
                r['phone'],
                r['email'],
                str(r['party_size']),
                r['date'],
                r['time'],
                r['special_requests'],
                r['status']
            ]) + '\n'
            f.write(line)


def load_waitlist():
    waitlist = []
    path = os.path.join(DATA_DIR, 'waitlist.txt')
    if not os.path.exists(path):
        return waitlist
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 5:
                try:
                    waitlist_id = int(parts[0])
                    party_size = int(parts[2])
                except ValueError:
                    continue
                waitlist.append({
                    'waitlist_id': waitlist_id,
                    'username': parts[1],
                    'party_size': party_size,
                    'join_time': parts[3],
                    'status': parts[4]
                })
    return waitlist


def save_waitlist(waitlist):
    path = os.path.join(DATA_DIR, 'waitlist.txt')
    with open(path, 'w', encoding='utf-8') as f:
        for w in waitlist:
            line = '|'.join([
                str(w['waitlist_id']),
                w['username'],
                str(w['party_size']),
                w['join_time'],
                w['status']
            ]) + '\n'
            f.write(line)


def load_reviews():
    reviews = []
    path = os.path.join(DATA_DIR, 'reviews.txt')
    if not os.path.exists(path):
        return reviews
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 6:
                try:
                    review_id = int(parts[0])
                    dish_id = int(parts[2])
                    rating = int(parts[3])
                except ValueError:
                    continue
                reviews.append({
                    'review_id': review_id,
                    'username': parts[1],
                    'dish_id': dish_id,
                    'rating': rating,
                    'review_text': parts[4],
                    'review_date': parts[5]
                })
    return reviews


def save_reviews(reviews):
    path = os.path.join(DATA_DIR, 'reviews.txt')
    with open(path, 'w', encoding='utf-8') as f:
        for r in reviews:
            line = '|'.join([
                str(r['review_id']),
                r['username'],
                str(r['dish_id']),
                str(r['rating']),
                r['review_text'],
                r['review_date']
            ]) + '\n'
            f.write(line)


def save_users(users):
    path = os.path.join(DATA_DIR, 'users.txt')
    with open(path, 'w', encoding='utf-8') as f:
        for u in users.values():
            line = '|'.join([
                u['username'],
                u['email'],
                u['phone'],
                u['full_name']
            ]) + '\n'
            f.write(line)


