    user_waitlist = None
    for w in waitlist_data:
        if w['username'] == username and w['status'] == 'Active':
            user_waitlist = w
            break

    if request.method == 'POST':
        party_size_str = request.form.get('party_size', '').strip()
        try:
            party_size = int(party_size_str)
            if party_size < 1:
                party_size = None
        except ValueError:
            party_size = None

        if party_size is not None and user_waitlist is None:
            max_id = max([w['waitlist_id'] for w in waitlist_data], default=0)
            new_id = max_id + 1
            join_time = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
            new_waitlist = {
                'waitlist_id': new_id,
                'username': username,
                'party_size': party_size,
                'join_time': join_time,
                'status': 'Active'
            }
            waitlist_data.append(new_waitlist)
            save_waitlist(waitlist_data)
            user_waitlist = new_waitlist

    user_position = None
    if user_waitlist is not None:
        active_waitlist = [w for w in waitlist_data if w['status'] == 'Active']

        def join_time_key(w):
            try:
                return datetime.strptime(w['join_time'], '%Y-%m-%d %H:%M:%S')
            except ValueError:
                return datetime.max

        active_waitlist.sort(key=join_time_key)

        for i, w in enumerate(active_waitlist, start=1):
            if w['waitlist_id'] == user_waitlist['waitlist_id']:
                user_position = i
                break

    return render_template('waitlist.html', user_position=user_position)


